#include <stdio.h>
#include <math.h>
#define MOD 1000003
long long power(long long x, long long y, long long p)
{
    long long res = 1;
    x = x % p;
    while (y > 0)
    {
        if (y & 1)
            res = (res * x) % p;
        y = y >> 1;
        x = (x * x) % p;
    }
    return res;
}
long long modInverse(long long n, long long p)
{
    return power(n, p - 2, p);
}
long long nCrModPFermat(long long n, long long r, long long p)
{
    if (n < r)
        return 0;
    if (r == 0)
        return 1;
    long long fac[n + 1];
    fac[0] = 1;
    for (int i = 1; i <= n; i++)
        fac[i] = (fac[i - 1] * i) % p;
    return (fac[n] * modInverse(fac[r], p) % p
            * modInverse(fac[n - r], p) % p)
           % p;
}
int main()
{
    int Q;
    scanf("%d", &Q);
    while (Q--)
    {
        long long N;
        scanf("%lld", &N);
        long long sum = 0;
        for (long long R = 0; R <= N / 2; R++)
        {
            sum = (sum + nCrModPFermat(N, R, MOD) - nCrModPFermat(N - R, R, MOD) + MOD) % MOD;
        }
        printf("%lld\n", sum);
    }
    return 0;
}

