        fac[0] = 1;
        for (int i = 1; i <= n; i++)
            fac[i] = (fac[i - 1] * i) % p;
        return (fac[(int)n] * modInverse(fac[(int)r], p) % p
                * modInverse(fac[(int)n - (int)r], p) % p)
               % p;
