def power(x, y, p):
    res = 1
    x = x % p
    while y > 0:
        if y % 2 == 1:
            res = (res * x) % p
        y = y >> 1
        x = (x * x) % p
    return res

def modInverse(n, p):
    return power(n, p - 2, p)

def nCrModPFermat(n, r, p):
    if n < r:
        return 0
    if r == 0:
        return 1
    fac = [0] * (n + 1)
    fac[0] = 1
    for i in range(1, n + 1):
        fac[i] = (fac[i - 1] * i) % p
    return (fac[n] * modInverse(fac[r], p) % p * modInverse(fac[n - r], p) % p) % p

def main():
    Q = int(input())
    for _ in range(Q):
        N = int(input())
        MOD = 10**6 + 3
        sum = 0
        for R in range(N // 2 + 1):
            sum = (sum + nCrModPFermat(N, R, MOD) - nCrModPFermat(N - R, R, MOD) + MOD) % MOD
        print(sum)
if __name__ == '__main__':
    main()

